const LabelWithBadge = ({ label, count }) => {
  return (
    <div
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        fontSize: "14px",
        paddingRight: "1px",
      }}
    >
      <span className="pr-4">{label}</span>
      {count > 0 && (
        <Badge
          count={count}
          size="small"
          style={{
            backgroundColor: count > 0 ? "#f50" : "#d9d9d9",
            fontSize: "10px",
          }}
        />
      )}
    </div>
  )
}

