import { Col, Menu, Row } from "antd"
import PropTypes from "prop-types"
import { useContext, useEffect, useState } from "react"
import { useLocation, useNavigate } from "react-router-dom"
import { StoreContext } from "src/contexts"
import { AdminMenuStyled } from "./styled"

const LayoutAdmin = ({
  children,
  selectedKey,
  setSelectedKey,
  menuAdmin,
  onClickMenu,
}) => {
  const navigate = useNavigate()
  const [collapsemenu, setcollapsemenu] = useState(false)
  const [hiddenMenu, setHiddenMenu] = useState(false)
  // const [openModalSearchSingle, setOpenModalSearchSingle] = useState(false)
  const { themeStore } = useContext(StoreContext)
  const { isDarkMode: themedark } = themeStore
  const location = useLocation()
  const onChange = menu => {
    onClickMenu(menu)
    !menu?.key?.includes("subkey") &&
      navigate(menu?.key?.replace("submenu", ""))
  }
  useEffect(() => {
    const bodyAdmin = document.getElementById("body-admin-scroll")
    !!bodyAdmin && bodyAdmin.scrollTo({ top: 0, left: 0, behavior: "smooth" })
    setSelectedKey(location?.pathname)
  }, [location?.pathname])
  // useEffect(() => {
  //   setcollapsemenu(true)
  // }, [])

  return (
    <Row style={{ flexWrap: "nowrap" }}>
      <Col
        span={"auto"}
        style={{
          border: "1px solid #ccc",
          transition: "all 0.2s",
          width: collapsemenu ? "82px" : "auto",
        }}
        // onMouseEnter={() => {
        //   setTimeout(() => setcollapsemenu(false), 300)
        // }}
        // onMouseLeave={() => {
        //   setTimeout(() => setcollapsemenu(true), 700)
        // }}
      >
        <AdminMenuStyled $themedark={themedark} $collapsemenu={collapsemenu}>
          <div
            className={`side-bar-wrapper d-flex flex-column justify-content-space-between`}
          >
            <Menu
              onClick={onChange}
              selectedKeys={selectedKey}
              mode="inline"
              defaultOpenKeys={[
                "subkey1",
                "subkey2",
                "subkey3",
                "subkey4",
                "subkey5",
                "subkey6",
                "subkey7",
              ]}
              style={{
                height: "100%",
                padding: 0,
              }}
              items={menuAdmin}
              // className="menu-antd-admin"
              className="menu-antd-user pt-5"
              theme={themedark ? "dark" : "light"}
              inlineCollapsed={collapsemenu}
            />
          </div>
        </AdminMenuStyled>
      </Col>
      <Col
        flex="auto"
        className="pt-12 pr-24"
        style={{
          width: 0,
          // height: "calc(100vh - 64px)",
          overflowY: "auto",
          paddingLeft: "16px",
          paddingBottom: "16px",
        }}
        id="body-admin-scroll"
      >
        {children}
      </Col>
    </Row>
  )
}

export default LayoutAdmin

LayoutAdmin.propTypes = {
  selectedKey: PropTypes.string,
  menuAdmin: PropTypes.array,
  onClickMenu: PropTypes.func,
}

LayoutAdmin.defaultProps = {
  selectedKey: "/",
  menuAdmin: [],
  onClickMenu: () => {},
}
