import { DoubleLeftOutlined } from "@ant-design/icons"
import { Col, Menu, Row } from "antd"
import PropTypes from "prop-types"
import { useContext, useEffect, useState } from "react"
import { useLocation, useNavigate } from "react-router-dom"
import ButtonCustom from "src/components/MyButton/Button"
import { StoreContext } from "src/contexts"
import { UserMenuStyled } from "./styled"
import "./styled.scss"
import ROUTER from "src/router/ROUTER"

const MOBILE_BREAKPOINT = 768 // breakpoint mobile

const LayoutUser = ({ children, selectedKey, menuUser, onClickMenu }) => {
  const navigate = useNavigate()
  const [collapsemenu, setcollapsemenu] = useState(false)
  const [isMobile, setIsMobile] = useState(false)
  const { themeStore } = useContext(StoreContext)
  const { isDarkMode: themedark } = themeStore
  const location = useLocation()

  const onChange = menu => {
    onClickMenu(menu)
    !menu?.key?.includes("subkey") &&
      navigate(menu?.key?.replace("submenu", ""))
  }

  // Scroll lên đầu khi đổi route
  useEffect(() => {
    document
      .getElementById("layout-user-scroll")
      ?.scrollTo({ top: 0, left: 0, behavior: "smooth" })
  }, [location?.pathname])

  // Detect mobile
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    handleResize() // chạy lần đầu
    window.addEventListener("resize", handleResize)
    return () => window.removeEventListener("resize", handleResize)
  }, [])

  return (
    <Row gutter={20} style={{ flexWrap: "nowrap" }}>
      {/* Sidebar: ẩn khi mobile */}
      {!isMobile && (
        <Col style={{ marginLeft: -20 }}>
          <UserMenuStyled
            themedark={themedark}
            collapsemenu={collapsemenu.toString()}
          >
            <div
              className={`side-bar-wrapper d-flex flex-column justify-content-space-between`}
            >
              <div>
                <Menu
                  onClick={onChange}
                  selectedKeys={selectedKey}
                  mode="inline"
                  defaultOpenKeys={[
                    "subkey1",
                    "subkey2",
                    "subkey6",
                    ROUTER.HOI_PHI,
                  ]}
                  items={menuUser}
                  className="menu-antd-user"
                  inlineCollapsed={collapsemenu}
                />
              </div>
              <ButtonCustom
                variant="text"
                ghost
                className="collapsed-item"
                onClick={() => setcollapsemenu(pre => !pre)}
              >
                <div className="d-flex-center">
                  <div className="collapsed-icon">
                    <DoubleLeftOutlined rotate={collapsemenu ? 180 : 0} />
                  </div>
                  {!collapsemenu && (
                    <div className="collapsed-title">Thu gọn</div>
                  )}
                </div>
              </ButtonCustom>
            </div>
          </UserMenuStyled>
        </Col>
      )}

      {/* Nội dung chính */}
      <Col
        flex="auto"
        className="pt-12 pr-24"
        style={{
          width: 0,
          overflowY: "auto",
        }}
        id="layout-user-scroll"
      >
        {children}
      </Col>
    </Row>
  )
}

export default LayoutUser

LayoutUser.propTypes = {
  selectedKey: PropTypes.string,
  menuUser: PropTypes.array,
  onClickMenu: PropTypes.func,
}

LayoutUser.defaultProps = {
  selectedKey: "/",
  menuUser: [],
  onClickMenu: () => {},
}
