import { LockOutlined, UserOutlined } from "@ant-design/icons"
import { Form } from "antd"
import { useContext, useState } from "react"
import { Link, useNavigate } from "react-router-dom"

import { StoreContext } from "src/contexts"
import STORAGE, { setStorage } from "src/lib/storage"
import ROUTER from "src/router/ROUTER"
import ButtonCustom from "../MyButton/Button"
import notice from "../Notice"

import loginImage from "src/assets/images/Frame_Login.png"
import logo from "src/assets/images/logo/logo3.png"
import { encode_data } from "src/lib/encoder"
import FormLoginSocial from "src/pages/SUPPORTPAGES/LoginGoogle/components/FormLoginSocial"
import AuthService from "src/services/AuthService"
import CheckboxCustom from "../CheckboxCustom"
import InputCustom from "../Input/InputCustom"
import CustomModal from "../Modal/CustomModal"
import SpinCustom from "../SpinCustom"
import "./LoginScreen.scss"
import ForgetModal from "./ForgetModal"

const LoginModal = ({
  open,
  onCancel,
  openForgetPassModal,
  setOpenForgetPassModal,
}) => {
  const navigate = useNavigate()
  const [loading, setLoading] = useState(false)
  const { loginStore, routerBeforeStore, userStore } = useContext(StoreContext)
  const { setIsLoginContext } = loginStore
  const { setRouterBeforeLogin } = routerBeforeStore
  const { setUser } = userStore
  const [email, setEmail] = useState("")
  const [openVerifyModal, setOpenVerifyModal] = useState(false)
  const onFinish = async values => {
    try {
      setLoading(true)
      const res = await AuthService.login({ ...values })
      if (res?.isOk) {
        setStorage(STORAGE.TOKEN, res?.Object?.Token)
        setStorage(STORAGE.USER_INFO, res?.Object)
        const data_hash = encode_data(STORAGE.TOKEN)
        setIsLoginContext(data_hash)
        setRouterBeforeLogin(undefined)
        setUser(res?.Object)
        onCancel()
        navigate(ROUTER.TONG_QUAN)
      }
    } catch (error) {
      console.log("error", error)
      notice({
        msg: "Lỗi hệ thống. Vui lòng thử lại sau.",
        isSuccess: false,
      })
    } finally {
      setLoading(false)
    }
  }

  return (
    <CustomModal
      open={open}
      onCancel={onCancel}
      footer={null}
      centered
      className="login-modal-custom"
      width={800}
    >
      <SpinCustom spinning={loading}>
        <div className="login-form-wrapper">
          <div className="login-image">
            <img src={loginImage} alt="Login image" />
          </div>

          <div className="login-form">
            <img src={logo} alt="Logo" className="login-logo-small" />
            <h2 className="login-title">Đăng nhập</h2>

            <Form layout="vertical" onFinish={onFinish} loading={loading}>
              <Form.Item
                name="username"
                rules={[
                  { required: true, message: "Vui lòng nhập tài khoản!" },
                ]}
              >
                <InputCustom
                  size="large"
                  prefix={<UserOutlined />}
                  placeholder="Số điện thoại hoặc email"
                />
              </Form.Item>

              <Form.Item
                name="password"
                rules={[
                  { required: true, message: "Vui lòng nhập mật khẩu!" },
                  { min: 6, message: "Mật khẩu ít nhất 6 ký tự!" },
                ]}
              >
                <InputCustom
                  type="password"
                  size="large"
                  prefix={<LockOutlined />}
                  placeholder="Mật khẩu"
                />
              </Form.Item>

              <div className="login-options">
                <Form.Item name="remember" valuePropName="checked" noStyle>
                  <CheckboxCustom>Nhớ mật khẩu</CheckboxCustom>
                </Form.Item>
                <Link
                  onClick={() => {
                    setOpenForgetPassModal(true)
                  }}
                  className="forget-pass"
                >
                  <i>Quên mật khẩu?</i>
                </Link>
              </div>

              <Form.Item>
                <ButtonCustom
                  htmlType="submit"
                  size="large"
                  className="login-button-primary"
                >
                  Đăng nhập
                </ButtonCustom>
              </Form.Item>
            </Form>
            <div className="center mb-8">Hoặc</div>
            <FormLoginSocial />
          </div>
        </div>
      </SpinCustom>
      <ForgetModal
        openForgetPassModal={openForgetPassModal}
        handleCancel={() => setOpenForgetPassModal(false)}
        handleLogin={() => {
          setOpenForgetPassModal(false)
          onCancel()
        }}
        setOpenVerifyModal={() => setOpenVerifyModal(true)}
        setEmail={setEmail}
      />
    </CustomModal>
  )
}

export default LoginModal
